import{_ as a,o as t,c as n,a2 as s}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 21 — Repeat (.)","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/21-repeat.md","filePath":"chapters/21-repeat.md"}'),o={name:"chapters/21-repeat.md"};function i(l,e,c,p,r,d){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="chapter-21-—-repeat" tabindex="-1">Chapter 21 — Repeat (.) <a class="header-anchor" href="#chapter-21-—-repeat" aria-label="Permalink to &quot;Chapter 21 — Repeat (.)&quot;">​</a></h1><blockquote><p><em>&quot;The dot command is the most powerful command in Vim.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 15 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>The dot command (<code>.</code>) repeats the <strong>last change</strong>.</p><p>It is perhaps Vim&#39;s single most powerful productivity feature.</p><hr><h1 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h1><p>Press <code>.</code> to repeat the last edit.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ciwHello        →   Change inner word to &quot;Hello&quot;</span></span>
<span class="line"><span>.               →   Change next word to &quot;Hello&quot;</span></span>
<span class="line"><span>.               →   Change next word to &quot;Hello&quot;</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dd              →   Delete a line</span></span>
<span class="line"><span>j               →   Move down</span></span>
<span class="line"><span>.               →   Delete this line too</span></span>
<span class="line"><span>j               →   Move down</span></span>
<span class="line"><span>.               →   Delete this line too</span></span></code></pre></div><hr><h1 id="what-counts-as-a-change" tabindex="-1">What Counts as a Change? <a class="header-anchor" href="#what-counts-as-a-change" aria-label="Permalink to &quot;What Counts as a Change?&quot;">​</a></h1><p>Everything from entering insert mode to leaving it.</p><p>Everything from one command until the next.</p><h2 id="changes" tabindex="-1">Changes <a class="header-anchor" href="#changes" aria-label="Permalink to &quot;Changes&quot;">​</a></h2><ul><li><code>dw</code> — delete word (one change)</li><li><code>ci&quot;text&quot;Esc</code> — change inside quotes (one change)</li><li><code>dd</code> — delete line (one change)</li><li><code>x</code> — delete character (one change)</li></ul><h2 id="non-changes" tabindex="-1">Non-Changes <a class="header-anchor" href="#non-changes" aria-label="Permalink to &quot;Non-Changes&quot;">​</a></h2><ul><li>Movement (<code>j</code>, <code>k</code>, <code>w</code>, <code>b</code>) — not changes</li><li>Search (<code>/pattern</code>) — not a change</li><li>Visual mode selection — not a change</li></ul><hr><h1 id="practical-example" tabindex="-1">Practical Example <a class="header-anchor" href="#practical-example" aria-label="Permalink to &quot;Practical Example&quot;">​</a></h1><p>You have a list with misspelled names:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Jhon</span></span>
<span class="line"><span>Jhon</span></span>
<span class="line"><span>Jhon</span></span>
<span class="line"><span>Jhon</span></span></code></pre></div><p>Fix the first one:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ciwJohn       →   Change &quot;Jhon&quot; to &quot;John&quot;</span></span></code></pre></div><p>Then move down and press <code>.</code> for each remaining line.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>j</span></span>
<span class="line"><span>.</span></span>
<span class="line"><span>j</span></span>
<span class="line"><span>.</span></span>
<span class="line"><span>j</span></span>
<span class="line"><span>.</span></span></code></pre></div><p>All fixed with one command and three dot presses.</p><hr><h1 id="the-dot-command-formula" tabindex="-1">The Dot Command Formula <a class="header-anchor" href="#the-dot-command-formula" aria-label="Permalink to &quot;The Dot Command Formula&quot;">​</a></h1><p>The dot command repeats:</p><p><code>Operator + Motion + Text</code></p><p>as a single unit.</p><p>This means compound commands like <code>ci&quot;</code>, <code>daw</code>, <code>c$</code> are all repeatable.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>.</code></td><td>Repeat last change</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li><code>.</code> repeats the last edit.</li><li>It works with any change (insert mode, delete, change, replace).</li><li>Combine with movement for rapid repetitive editing.</li><li>It is the single most valuable Vim command.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Change a word, move to another word, press <code>.</code>.</li><li>Delete a line, move down, press <code>.</code>.</li><li>Change inside quotes with <code>ci&quot;</code>, move to next quote, press <code>.</code>.</li><li>Add a semicolon at the end of multiple lines using <code>A;</code> then <code>.</code>.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./22-visual-mode-character.html"><strong>Chapter 22 — Visual Mode: Character Selection</strong></a></p><p>Select text character by character in visual mode.</p>`,50)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
